# 1. التحقق من وجود قيمة داخل حقل اسم الشيخ
if doc.sheikh_name:
    
    # تنظيف الاسم تماماً من أي مسافات زائدة في البداية والنهاية
    name_stripped = doc.sheikh_name.strip()
    
    # 2. التحقق الذكي لمنع تكرار الكلمة حتى لو كتبت بمسافات مختلفة
    if not name_stripped.startswith("الشيخ"):
        doc.sheikh_name = f"الشيخ {name_stripped}"
    else:
        # إذا كانت الكلمة موجودة بالفعل، نعيد تنظيف السلسلة كاملة لضمان التنسيق
        # نقوم بتقسيم النص وإعادة تجميعه بمسافة واحدة منضبطة
        parts = name_stripped.split()
        if parts[0] == "الشيخ" and len(parts) > 1:
            doc.sheikh_name = "الشيخ " + " ".join(parts[1:])
        else:
            doc.sheikh_name = name_stripped

